#!/usr/bin/env node
/**
 * Knowledge Graph Validation Script
 * Validates graph structure, referential integrity, and completeness
 */

const fs = require('fs');

const VALID_NODE_TYPES = new Set([
  'file', 'function', 'class', 'module', 'concept', 'config',
  'document', 'service', 'table', 'endpoint', 'pipeline', 'schema',
  'resource', 'domain', 'flow', 'step'
]);

const VALID_EDGE_TYPES = new Set([
  'imports', 'exports', 'contains', 'inherits', 'implements', 'calls',
  'subscribes', 'publishes', 'middleware', 'reads_from', 'writes_to',
  'transforms', 'validates', 'depends_on', 'tested_by', 'configures',
  'related', 'similar_to', 'deploys', 'serves', 'migrates', 'documents',
  'provisions', 'routes', 'defines_schema', 'triggers', 'contains_flow',
  'flow_step', 'cross_domain'
]);

const VALID_COMPLEXITY = new Set(['simple', 'moderate', 'complex']);
const VALID_DIRECTIONS = new Set(['forward', 'backward', 'bidirectional']);

const NODE_PREFIX_MAP = {
  'file': 'file:',
  'function': 'function:',
  'class': 'class:',
  'module': 'module:',
  'concept': 'concept:',
  'config': 'config:',
  'document': 'document:',
  'service': 'service:',
  'table': 'table:',
  'endpoint': 'endpoint:',
  'pipeline': 'pipeline:',
  'schema': 'schema:',
  'resource': 'resource:',
  'domain': 'domain:',
  'flow': 'flow:',
  'step': 'step:'
};

// Expected edge types for quality checks
const NODE_EXPECTED_EDGES = {
  'document': ['documents'],
  'service': ['deploys', 'depends_on'],
  'pipeline': ['triggers'],
  'table': ['migrates', 'defines_schema'],
  'schema': ['defines_schema'],
  'domain': ['contains_flow'],
  'flow': ['flow_step']
};

function main() {
  const inputPath = process.argv[2];
  const outputPath = process.argv[3];

  if (!inputPath || !outputPath) {
    console.error('Usage: node ua-graph-validate.js <input-graph.json> <output-results.json>') > stderr;
    process.exit(1);
  }

  let graph;
  try {
    const content = fs.readFileSync(inputPath, 'utf8');
    graph = JSON.parse(content);
  } catch (err) {
    console.error('Error reading/parsing graph file:', err.message, '\n', err.stack);
    process.exit(1);
  }

  const issues = [];
  const warnings = [];
  const stats = {
    totalNodes: 0,
    totalEdges: 0,
    totalLayers: 0,
    tourSteps: 0,
    nodeTypes: {},
    edgeTypes: {}
  };

  // Build node ID set for referential integrity checks
  const nodeIds = new Set();
  const nodesArray = graph.nodes || [];

  // Check if it's a domain graph
  const isDomainGraph = nodesArray.some(n =>
    n.type === 'domain' || n.type === 'flow' || n.type === 'step'
  );

  // ========== Check 1: Schema Validation ==========
  const nodes = graph.nodes || [];
  const edges = graph.edges || [];
  const layers = graph.layers || [];
  const tour = graph.tour || {};

  stats.totalNodes = nodes.length;
  stats.totalEdges = edges.length;
  stats.totalLayers = layers.length;
  stats.tourSteps = tour.steps ? tour.steps.length : 0;

  // Node schema validation
  for (let i = 0; i < nodes.length; i++) {
    const node = nodes[i];
    const idx = `node[${i}]`;

    // Required fields
    if (!node.id || typeof node.id !== 'string' || node.id.trim() === '') {
      issues.push(`${idx}: Missing or empty 'id' field`);
    }

    if (!node.type || typeof node.type !== 'string') {
      issues.push(`${idx}: Missing or invalid 'type' field`);
    } else if (!VALID_NODE_TYPES.has(node.type)) {
      issues.push(`${idx}: Invalid node type '${node.type}'. Valid types: ${[...VALID_NODE_TYPES].join(', ')}`);
    }

    if (!node.name || typeof node.name !== 'string' || node.name.trim() === '') {
      issues.push(`${idx}: Missing or empty 'name' field`);
    }

    if (!node.summary || typeof node.summary !== 'string' || node.summary.trim() === '') {
      issues.push(`${idx}: Missing or empty 'summary' field`);
    }

    if (!Array.isArray(node.tags) || node.tags.length === 0) {
      issues.push(`${idx}: Missing or empty 'tags' array`);
    } else {
      for (const tag of node.tags) {
        if (typeof tag !== 'string' || tag !== tag.toLowerCase() || tag.includes('_')) {
          warnings.push(`${idx}: Tag '${tag}' should be lowercase and hyphenated`);
        }
      }
    }

    if (!node.complexity || typeof node.complexity !== 'string') {
      issues.push(`${idx}: Missing or invalid 'complexity' field`);
    } else if (!VALID_COMPLEXITY.has(node.complexity)) {
      issues.push(`${idx}: Invalid complexity '${node.complexity}'. Valid values: simple, moderate, complex`);
    }

    // Track node type stats
    if (node.type) {
      stats.nodeTypes[node.type] = (stats.nodeTypes[node.type] || 0) + 1;
    }

    // Add to ID set if has valid ID
    if (node.id && typeof node.id === 'string') {
      nodeIds.add(node.id);
    }
  }

  // Edge schema validation
  for (let i = 0; i < edges.length; i++) {
    const edge = edges[i];
    const idx = `edge[${i}]`;

    if (!edge.source || typeof edge.source !== 'string' || edge.source.trim() === '') {
      issues.push(`${idx}: Missing or empty 'source' field`);
    }

    if (!edge.target || typeof edge.target !== 'string' || edge.target.trim() === '') {
      issues.push(`${idx}: Missing or empty 'target' field`);
    }

    if (!edge.type || typeof edge.type !== 'string') {
      issues.push(`${idx}: Missing or invalid 'type' field`);
    } else if (!VALID_EDGE_TYPES.has(edge.type)) {
      issues.push(`${idx}: Invalid edge type '${edge.type}'. Valid types: ${[...VALID_EDGE_TYPES].join(', ')}`);
    }

    if (!edge.direction || typeof edge.direction !== 'string') {
      issues.push(`${idx}: Missing or invalid 'direction' field`);
    } else if (!VALID_DIRECTIONS.has(edge.direction)) {
      issues.push(`${idx}: Invalid direction '${edge.direction}'. Valid values: forward, backward, bidirectional`);
    }

    if (typeof edge.weight !== 'number' || edge.weight < 0.0 || edge.weight > 1.0) {
      issues.push(`${idx}: Edge weight must be a number between 0.0 and 1.0, got: ${edge.weight}`);
    }

    // Track edge type stats
    if (edge.type) {
      stats.edgeTypes[edge.type] = (stats.edgeTypes[edge.type] || 0) + 1;
    }
  }

  // ========== Check 2: Referential Integrity ==========
  for (let i = 0; i < edges.length; i++) {
    const edge = edges[i];
    const idx = `edge[${i}]`;

    if (edge.source && !nodeIds.has(edge.source)) {
      issues.push(`${idx}: Edge references non-existent source node '${edge.source}'`);
    }
    if (edge.target && !nodeIds.has(edge.target)) {
      issues.push(`${idx}: Edge references non-existent target node '${edge.target}'`);
    }
  }

  // Layer nodeIds references
  for (let li = 0; li < layers.length; li++) {
    const layer = layers[li];
    const lidx = `layer[${li}]`;
    if (layer.nodeIds) {
      for (const nid of layer.nodeIds) {
        if (!nodeIds.has(nid)) {
          issues.push(`${lidx}: Layer references non-existent node '${nid}'`);
        }
      }
    }
  }

  // Tour step nodeIds references
  if (tour.steps) {
    for (let si = 0; si < tour.steps.length; si++) {
      const step = tour.steps[si];
      const sidx = `tour.step[${si}]`;
      if (step.nodeIds) {
        for (const nid of step.nodeIds) {
          if (!nodeIds.has(nid)) {
            issues.push(`${sidx}: Tour step references non-existent node '${nid}'`);
          }
        }
      }
    }
  }

  // ========== Check 3: Completeness ==========
  if (nodes.length === 0) {
    issues.push('No nodes exist in the graph');
  }
  if (edges.length === 0) {
    issues.push('No edges exist in the graph');
  }
  if (layers.length === 0) {
    if (isDomainGraph) {
      warnings.push('Domain graph has no layers (acceptable for domain graphs)');
    } else {
      issues.push('No layers exist in the graph');
    }
  }
  if (!tour.steps || tour.steps.length === 0) {
    if (isDomainGraph) {
      warnings.push('Domain graph has no tour steps (acceptable for domain graphs)');
    } else {
      issues.push('No tour steps exist in the graph');
    }
  }

  // ========== Check 4: Layer Coverage ==========
  const fileLevelTypes = new Set(['file', 'config', 'document', 'service', 'pipeline', 'table', 'schema', 'resource', 'endpoint']);
  const fileLevelNodes = nodes.filter(n => fileLevelTypes.has(n.type));
  const nodesInLayers = new Set();

  for (const layer of layers) {
    if (!layer.nodeIds || layer.nodeIds.length === 0) {
      issues.push(`Layer '${layer.name || li}' has empty nodeIds array`);
    }
    if (layer.nodeIds) {
      for (const nid of layer.nodeIds) {
        if (nodesInLayers.has(nid)) {
          issues.push(`Node '${nid}' appears in multiple layers`);
        }
        nodesInLayers.add(nid);
      }
    }
  }

  // File-level nodes missing from all layers
  if (!isDomainGraph || layers.length > 0) {
    for (const node of fileLevelNodes) {
      if (!nodesInLayers.has(node.id)) {
        issues.push(`File-level node '${node.id}' is missing from all layers`);
      }
    }
  }

  // ========== Check 5: Uniqueness ==========
  const seenIds = new Map();
  for (let i = 0; i < nodes.length; i++) {
    const id = nodes[i].id;
    if (id) {
      if (seenIds.has(id)) {
        issues.push(`Duplicate node ID '${id}' at indices ${seenIds.get(id)} and ${i}`);
      } else {
        seenIds.set(id, i);
      }
    }
  }

  // ========== Check 6: Tour Validation ==========
  if (tour.steps && tour.steps.length > 0) {
    if (tour.steps.length < 5) {
      warnings.push(`Tour has only ${tour.steps.length} steps, expected 5-15`);
    }
    if (tour.steps.length > 15) {
      warnings.push(`Tour has ${tour.steps.length} steps, expected 5-15`);
    }

    const orders = tour.steps.map(s => s.order);
    const orderSet = new Set();
    let expectedOrder = 1;
    for (const step of tour.steps) {
      if (!step.nodeIds || step.nodeIds.length === 0) {
        warnings.push(`Tour step ${step.order} has no nodeIds`);
      }
      if (step.order !== expectedOrder) {
        warnings.push(`Tour step order ${step.order} is not sequential (expected ${expectedOrder})`);
      }
      if (orderSet.has(step.order)) {
        issues.push(`Duplicate tour order value: ${step.order}`);
      }
      orderSet.add(step.order);
      expectedOrder++;
    }
  }

  // ========== Check 7: Quality Checks ==========
  // Summary quality
  for (const node of nodes) {
    if (node.summary) {
      const name = node.name || '';
      const summary = node.summary;
      if (summary.length< 20) {
        warnings.push(`Node '${node.id}' has a very short summary`);
      }
      if (summary === name || summary === node.id) {
        warnings.push(`Node '${node.id}' summary is just the name/ID`);
      }
    }

    // Self-referencing edges
    for (const edge of edges) {
      if (edge.source === edge.target) {
        warnings.push(`Self-referencing edge: ${edge.source} -> ${edge.target}`);
      }
    }
  }

  // Orphan nodes
  const connectedNodes = new Set();
  for (const edge of edges) {
    if (edge.source) connectedNodes.add(edge.source);
    if (edge.target) connectedNodes.add(edge.target);
  }
  for (const node of nodes) {
    if (node.id && !connectedNodes.has(node.id)) {
      warnings.push(`Orphan node '${node.id}' has no connecting edges`);
    }
  }

  // ========== Check 8: Non-Code Node Quality Checks ==========
  for (const node of nodes) {
    const expectedTypes = NODE_EXPECTED_EDGES[node.type];
    if (expectedTypes) {
      const hasExpectedEdge = edges.some(e =>
        e.source === node.id && expectedTypes.includes(e.type)
      );
      if (!hasExpectedEdge) {
        warnings.push(`Node '${node.id}' (type: ${node.type}) has no expected ${expectedTypes.join('/')} edge`);
      }
    }
  }

  // ========== Check 9: Node Type / ID Prefix Consistency ==========
  for (const node of nodes) {
    if (node.id && node.type) {
      const expectedPrefix = NODE_PREFIX_MAP[node.type];
      if (expectedPrefix && !node.id.startsWith(expectedPrefix)) {
        warnings.push(`Node '${node.id}' has type '${node.type}' but ID should start with '${expectedPrefix}'`);
      }
    }
  }

  // Write results
  const result = {
    scriptCompleted: true,
    issues,
    warnings,
    stats
  };

  try {
    fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
  } catch (err) {
    console.error('Error writing output file:', err.message);
    process.exit(1);
  }

  console.error('Validation complete. Issues:', issues.length, 'Warnings:', warnings.length);
  process.exit(0);
}

main();

